const registryAny = SUGGESTED_ACTION_REGISTRY;
const ACTION_DEFINITIONS = registryAny.actions || {};
const ALIAS_TO_CANONICAL = {
  "reply": "send_reply",
  "ask_staff": "send_chat_message",
  "staff_chat_message": "send_chat_message",
  "create_subscription": "update_plan",
  "update_subscription": "update_plan",
  "create_payment_subscription": "update_plan",
  "create_claimable": "claimable",
  "fill_bk_case": "update_bk_case",
  "update_trustee_upload": "trustee_upload",
  "set_installments": "filing_fee_installments",
  "approve_doc": "approve_document",
  "finish_item": "complete_item",
  "open_objection": "objection",
  "update_objection": "objection",
  "open_garnishment": "garnishment",
  "update_garnishment": "garnishment",
  "convert": "convert_chapter"
};
const EVIDENCE_KIND_SET = new Set(registryAny.evidenceKinds || []);
const PAYMENT_CONFIRMATION_RE = /\b(payment|charge|card)\b.{0,60}\b(received|processed|went through|succeeded|successful|paid|charged)\b|\b(received|processed|charged)\b.{0,60}\b(payment|charge|card)\b/i;
const DOCUMENT_APPROVAL_CONFIRMATION_RE = /\b(document|documents|statement|statements|upload|uploaded|file|files|pay\s*stub|pay\s*stubs|tax\s*return|tax\s*returns)\b.{0,100}\b(approved|accepted|verified|received and verified)\b|\b(approved|accepted|verified|received and verified)\b.{0,100}\b(document|documents|statement|statements|upload|uploaded|file|files|pay\s*stub|pay\s*stubs|tax\s*return|tax\s*returns)\b/i;

export const ACTION_TYPES = Object.keys(ACTION_DEFINITIONS);
export const EVIDENCE_KINDS = [...(registryAny.evidenceKinds || [])];
export const REVIEW_CONTEXT_PANELS = registryAny.reviewContextPanels || {};
export const BK_CASE_FIELD_META = registryAny.bkCaseFieldMeta || {};

const isObj = (value) => !!value && typeof value === 'object' && !Array.isArray(value);
const str = (value) => (typeof value === 'string' ? value.trim() : value == null ? '' : String(value).trim());
const pathJoin = (parts) => parts.filter(Boolean).join('.');

function valueAt(source, path) {
  if (!path) return undefined;
  return String(path).split('.').reduce((acc, part) => (acc && typeof acc === 'object' ? acc[part] : undefined), source);
}

function setValueAt(source, path, value) {
  const parts = String(path).split('.');
  let current = source;
  for (let i = 0; i < parts.length - 1; i += 1) {
    const part = parts[i];
    if (!isObj(current[part])) current[part] = {};
    current = current[part];
  }
  current[parts[parts.length - 1]] = value;
}

function receivedType(value) {
  if (Array.isArray(value)) return 'array';
  if (value === null) return 'null';
  return typeof value;
}

function validScalar(value, rule) {
  if (rule.type === 'string') return typeof value === 'string' && (!!rule.allowEmpty || value.trim().length > 0);
  if (rule.type === 'number') return typeof value === 'number' && Number.isFinite(value) && (!rule.positive || value > 0);
  if (rule.type === 'boolean') return typeof value === 'boolean';
  if (rule.type === 'array') return Array.isArray(value) && (!rule.minItems || value.length >= rule.minItems);
  if (rule.type === 'object') return isObj(value);
  return value !== undefined && value !== null;
}

function makeError(action, path, code, message, expected, received) {
  return {
    action_key: str(action?.key || action?.id) || undefined,
    type: str(action?.type) || undefined,
    path: path || undefined,
    code,
    message,
    expected,
    received,
  };
}

function checkEnum(action, rule, value, errors, path) {
  if (Array.isArray(rule.enum) && !rule.enum.includes(value)) {
    errors.push(makeError(action, path, 'invalid_enum', `${path} must be one of: ${rule.enum.join(', ')}`, rule.enum, value));
  }
}

function checkSendReplyBodies(action, rule, value, errors, path) {
  if (!isObj(value)) return;
  const defaultChannel = str(valueAt(action, 'params.default_channel') || valueAt(action, 'params.channel'));
  const channels = ['sms', 'email', 'support'];
  const filled = channels.filter((channel) => isObj(value[channel]) && str(value[channel].body));
  if (!filled.length) {
    errors.push(makeError(action, path, 'missing_reply_body', 'params.bodies must contain at least one channel body', 'bodies.sms.body or bodies.email.body or bodies.support.body', value));
  }
  if (defaultChannel && (!isObj(value[defaultChannel]) || !str(value[defaultChannel].body))) {
    errors.push(makeError(action, `${path}.${defaultChannel}.body`, 'missing_default_channel_body', `params.bodies.${defaultChannel}.body is required because default_channel is ${defaultChannel}`, 'non-empty string', value[defaultChannel]));
  }
}

function checkStaffChatBody(action, rule, value, errors, path) {
  if (typeof value === 'string' && /^\s*@\S/.test(value)) {
    errors.push(makeError(action, path, 'structured_mention_double_tag', 'send_chat_message.params.message must not start with an @mention; put the mention target in params.workflow_role/assignee and keep message as plain text', 'plain message text', value));
  }
}

function checkTrusteeUploadAction(action, rule, value, errors, path) {
  if (value !== 'uploaded' && value !== 'unable' && value !== 'not_needed') {
    errors.push(makeError(action, path, 'invalid_trustee_upload_action', 'trustee_upload.params.action must be uploaded, unable, or not_needed', ['uploaded', 'unable', 'not_needed'], value));
  }
}

function checkBkCaseFields(action, rule, value, errors, path) {
  if (!Array.isArray(value)) return;
  value.forEach((field, index) => {
    const fieldPath = `${path}.${index}`;
    if (!isObj(field)) {
      errors.push(makeError(action, fieldPath, 'invalid_field', 'BK field proposal must be an object', 'object', receivedType(field)));
      return;
    }
    const key = str(field.key);
    const meta = key ? BK_CASE_FIELD_META[key] : null;
    if (!key) {
      errors.push(makeError(action, `${fieldPath}.key`, 'missing_field_key', 'BK field proposal is missing key', 'known bk_case field key', field.key));
      return;
    }
    if (!meta) {
      errors.push(makeError(action, `${fieldPath}.key`, 'unknown_bk_case_field', `${key} is not in bkCaseFieldMeta`, Object.keys(BK_CASE_FIELD_META), key));
      return;
    }
    const hasValue = Object.prototype.hasOwnProperty.call(field, 'value') && field.value !== null && field.value !== '';
    if (!hasValue) {
      errors.push(makeError(action, `${fieldPath}.value`, 'missing_field_value', `${key} must include a value`, meta.type, field.value));
      return;
    }
    if (meta.type === 'number' && (typeof field.value !== 'number' || !Number.isFinite(field.value))) {
      errors.push(makeError(action, `${fieldPath}.value`, 'invalid_field_value', `${key} must be a number`, 'number', receivedType(field.value)));
    }
    if ((meta.type === 'date' || meta.type === 'datetime' || meta.type === 'text' || meta.type === 'textarea') && typeof field.value !== 'string') {
      errors.push(makeError(action, `${fieldPath}.value`, 'invalid_field_value', `${key} must be a string`, meta.type, receivedType(field.value)));
    }
    if (meta.type === 'select' && (!meta.options || !meta.options.includes(String(field.value)))) {
      errors.push(makeError(action, `${fieldPath}.value`, 'invalid_field_value', `${key} must be one of: ${(meta.options || []).join(', ')}`, meta.options || [], field.value));
    }
  });
}

function checkCustom(action, rule, value, errors, path) {
  if (rule.custom === 'send_reply_bodies') checkSendReplyBodies(action, rule, value, errors, path);
  if (rule.custom === 'send_chat_message_body') checkStaffChatBody(action, rule, value, errors, path);
  if (rule.custom === 'trustee_upload_action') checkTrusteeUploadAction(action, rule, value, errors, path);
  if (rule.custom === 'bk_case_fields') checkBkCaseFields(action, rule, value, errors, path);
}

function checkRule(action, rule, errors) {
  if (Array.isArray(rule.oneOf)) {
    const found = rule.oneOf.find((path) => validScalar(valueAt(action, path), rule));
    if (!found) {
      errors.push(makeError(action, rule.oneOf.join('|'), 'missing_required_param', `one of ${rule.oneOf.join(', ')} is required`, rule.type || 'value', rule.oneOf.map((path) => ({ path, received: receivedType(valueAt(action, path)) }))));
    }
    return;
  }

  const path = rule.path;
  const value = valueAt(action, path);
  if (!validScalar(value, rule)) {
    errors.push(makeError(action, path, 'missing_required_param', `${path} must be ${rule.positive ? 'a positive ' : ''}${rule.type || 'present'}`, rule.type, receivedType(value)));
    return;
  }
  checkEnum(action, rule, value, errors, path);
  checkCustom(action, rule, value, errors, path);
}

function validateEvidenceItems(evidence, errors, owner, basePath) {
  evidence.forEach((item, index) => {
    const path = `${basePath}.${index}`;
    if (!isObj(item)) {
      errors.push(makeError(owner, path, 'invalid_evidence', 'evidence item must be an object', 'object', receivedType(item)));
      return;
    }
    const kind = str(item.kind);
    if (!EVIDENCE_KIND_SET.has(kind)) {
      errors.push(makeError(owner, `${path}.kind`, 'invalid_evidence_kind', `evidence kind must be one of: ${EVIDENCE_KINDS.join(', ')}`, EVIDENCE_KINDS, item.kind));
    }
  });
}

function validateActionEvidence(action, def, errors) {
  const evidence = action.evidence;
  if (!Array.isArray(evidence)) {
    errors.push(makeError(action, 'evidence', 'evidence_must_be_array', 'action.evidence must be an array, even when empty', 'array', receivedType(evidence)));
    return;
  }
  validateEvidenceItems(evidence, errors, action, 'evidence');
  for (const hard of def.evidence?.hard || []) {
    const allowed = hard.allowedKinds || [];
    const matches = evidence.filter((item) => isObj(item) && allowed.includes(str(item.kind)) && (!hard.quoteRequired || str(item.quote)));
    if (matches.length < Number(hard.minCount || 1)) {
      errors.push(makeError(action, 'evidence', 'missing_required_evidence', hard.description || `requires at least ${hard.minCount || 1} evidence item`, { minCount: hard.minCount || 1, allowedKinds: allowed, quoteRequired: !!hard.quoteRequired }, matches.length));
    }
  }
}

function mergeParamsForValidation(action, override) {
  const next = { ...action };
  const params = isObj(action.params) ? { ...action.params } : {};
  if (isObj(override)) {
    Object.assign(params, override);
  }
  next.params = params;
  return next;
}

function overrideForAction(overrides, action, canonicalType) {
  if (!isObj(overrides)) return {};
  const byKey = str(action.key || action.id);
  const candidates = [byKey, canonicalType, str(action.type)].filter(Boolean);
  for (const key of candidates) {
    if (isObj(overrides[key])) return overrides[key];
  }
  return {};
}

function validateAction(action, def, options, errors) {
  const mode = options.mode === 'execute' ? 'execute' : 'propose';
  const rules = mode === 'execute'
    ? [...(def.requiredToPropose || []), ...(def.requiredToExecute || [])]
    : [...(def.requiredToPropose || [])];

  if (def.lane === 'perform' && typeof action.sequence !== 'number') {
    errors.push(makeError(action, 'sequence', 'missing_sequence', 'perform-lane actions must include a numeric sequence', 'number', receivedType(action.sequence)));
  }
  if (def.lane === 'perform' && !str(action.key || action.id)) {
    errors.push(makeError(action, 'key', 'missing_action_key', 'perform-lane actions must include a stable key', 'non-empty string', action.key || action.id));
  }
  if (def.lane === 'editor') {
    if (action.sequence !== undefined && registryAny.commonValidation?.rejectEditorSequence) {
      errors.push(makeError(action, 'sequence', 'editor_sequence_not_allowed', 'editor-lane actions must not include sequence', 'absent', action.sequence));
    }
    if (action.in_plan === true && registryAny.commonValidation?.rejectEditorInPlan && !def.allowInPlan) {
      errors.push(makeError(action, 'in_plan', 'editor_in_plan_not_allowed', 'editor-lane actions must not set in_plan=true', 'false or absent', action.in_plan));
    }
  }
  for (const rule of rules) checkRule(action, rule, errors);
  // Human-initiated (inline/manual) actions carry the supervisor's own authority, so the AI-evidence gate
  // (def.evidence.hard) does not apply — params are still fully validated above.
  if (!options.skipEvidence) validateActionEvidence(action, def, errors);
}

function bodyTextsForSendReply(action) {
  const params = isObj(action.params) ? action.params : {};
  const bodies = isObj(params.bodies) ? params.bodies : {};
  const out = [];
  for (const channel of ['sms', 'email', 'support']) {
    if (isObj(bodies[channel]) && str(bodies[channel].body)) out.push(str(bodies[channel].body));
  }
  if (str(params.body)) out.push(str(params.body));
  if (str(params.message)) out.push(str(params.message));
  return out;
}

function validatePaymentConfirmationOrdering(actions, errors) {
  const chargeSequences = actions
    .filter((action) => canonicalActionType(action.type) === 'charge_payment')
    .map((action) => Number(action.sequence))
    .filter((sequence) => Number.isFinite(sequence));
  if (!chargeSequences.length) return;
  for (const action of actions) {
    if (canonicalActionType(action.type) !== 'send_reply') continue;
    const sequence = Number(action.sequence);
    if (!Number.isFinite(sequence)) continue;
    const confirmsPayment = bodyTextsForSendReply(action).some((body) => PAYMENT_CONFIRMATION_RE.test(body));
    if (confirmsPayment && !chargeSequences.some((chargeSeq) => chargeSeq < sequence)) {
      errors.push(makeError(action, 'sequence', 'payment_confirmation_before_charge', 'a send_reply that says or implies payment was received/processed must run after charge_payment', 'charge_payment sequence lower than send_reply', sequence));
    }
  }
}

function validateDocumentApprovalOrdering(actions, errors) {
  const approvalSequences = actions
    .filter((action) => canonicalActionType(action.type) === 'approve_document')
    .map((action) => Number(action.sequence))
    .filter((sequence) => Number.isFinite(sequence));
  if (!approvalSequences.length) return;
  for (const action of actions) {
    if (canonicalActionType(action.type) !== 'send_reply') continue;
    const sequence = Number(action.sequence);
    if (!Number.isFinite(sequence)) continue;
    const confirmsDocumentApproval = bodyTextsForSendReply(action).some((body) => DOCUMENT_APPROVAL_CONFIRMATION_RE.test(body));
    if (confirmsDocumentApproval && !approvalSequences.some((approvalSeq) => approvalSeq < sequence)) {
      errors.push(makeError(action, 'sequence', 'document_approval_before_reply', 'a send_reply that says or implies documents were approved must run after approve_document', 'approve_document sequence lower than send_reply', sequence));
    }
  }
}

export function canonicalActionType(type) {
  const t = str(type);
  if (!t) return '';
  if (ACTION_DEFINITIONS[t]) return t;
  return ALIAS_TO_CANONICAL[t] || '';
}

export function actionDefinitionFor(type) {
  const canonical = canonicalActionType(type);
  return canonical ? ACTION_DEFINITIONS[canonical] || null : null;
}

export function isPerformActionType(type) {
  return actionDefinitionFor(type)?.lane === 'perform';
}

export function validateSuggestedActions(actions, options = {}) {
  const errors = [];
  const normalizedActions = [];
  if (!Array.isArray(actions)) {
    return { ok: false, errors: [makeError(null, 'actions', 'actions_must_be_array', 'actions must be an array', 'array', receivedType(actions))], actions: [] };
  }
  const lanes = Array.isArray(options.lanes) ? options.lanes : options.lane ? [options.lane] : null;
  for (let index = 0; index < actions.length; index += 1) {
    const original = actions[index];
    if (!isObj(original)) {
      errors.push(makeError({ key: `actions.${index}` }, `actions.${index}`, 'invalid_action', 'action must be an object', 'object', receivedType(original)));
      continue;
    }
    const canonical = canonicalActionType(original.type);
    if (!canonical) {
      errors.push(makeError(original, `actions.${index}.type`, 'unknown_action_type', `unknown action type ${str(original.type) || '(empty)'}`, ACTION_TYPES, original.type));
      continue;
    }
    const def = ACTION_DEFINITIONS[canonical];
    if (lanes && !lanes.includes(def.lane)) continue;
    const normalized = { ...original, type: canonical };
    const override = overrideForAction(options.overrides, original, canonical);
    const actionForValidation = options.mode === 'execute' ? mergeParamsForValidation(normalized, override) : normalized;
    validateAction(actionForValidation, def, options, errors);
    normalizedActions.push(actionForValidation);
  }
  if (registryAny.commonValidation?.chargeBeforeConfirmingReply && (!lanes || lanes.includes('perform'))) {
    validatePaymentConfirmationOrdering(normalizedActions, errors);
  }
  if (registryAny.commonValidation?.approveDocumentBeforeConfirmingReply && (!lanes || lanes.includes('perform'))) {
    validateDocumentApprovalOrdering(normalizedActions, errors);
  }
  return { ok: errors.length === 0, errors, actions: normalizedActions };
}

export function validateCardEvidence(evidence, options = {}) {
  const errors = [];
  const value = evidence === undefined || evidence === null ? [] : evidence;
  const owner = { key: 'card', type: 'card' };
  if (!Array.isArray(value)) {
    return { ok: false, errors: [makeError(owner, 'evidence', 'evidence_must_be_array', 'card.evidence must be an array', 'array', receivedType(value))] };
  }
  validateEvidenceItems(value, errors, owner, 'evidence');
  const recommendedAction = str(options.recommendedAction);
  const requiredWhenNoActions = registryAny.cardEvidence?.requiredWhenNoActions || [];
  if (!options.hasActions && requiredWhenNoActions.includes(recommendedAction) && value.length < Number(registryAny.cardEvidence?.minCount || 1)) {
    errors.push(makeError(owner, 'evidence', 'missing_card_evidence', `${recommendedAction} cards without executable actions require card-level evidence`, { minCount: registryAny.cardEvidence?.minCount || 1 }, value.length));
  }
  return { ok: errors.length === 0, errors };
}

export function validateActionSuggestionDocument(suggestion, options = {}) {
  const s = isObj(suggestion) ? suggestion : {};
  const actions = Array.isArray(s.actions) ? s.actions : [];
  const actionResult = validateSuggestedActions(actions, { ...options, mode: options.mode || 'propose' });
  const cardEvidenceResult = validateCardEvidence(s.evidence, {
    recommendedAction: s.recommended_action || s.context?.recommended_action,
    hasActions: actionResult.actions.length > 0,
  });
  const errors = [...actionResult.errors, ...cardEvidenceResult.errors];
  if (s.actions !== undefined && !Array.isArray(s.actions)) {
    errors.push(makeError({ key: 'card', type: 'card' }, 'actions', 'actions_must_be_array', 'actions must be an array', 'array', receivedType(s.actions)));
  }
  return { ok: errors.length === 0, errors, actions: actionResult.actions };
}

